    assert_eq!(
        fields[4].kind,
        FieldKind::DocumentInfo("NUMPAGES".to_string())
    );
    assert_eq!(fields[4].result, "12");
    assert_eq!(
        fields[5].kind,
        FieldKind::DocumentInfo("EDITTIME".to_string())
    );
    assert_eq!(fields[5].result, "42");
