    assert_eq!(fields[4].computed_result, None);
    assert_eq!(fields[5].kind, FieldKind::Dynamic("NEXTIF".to_string()));
    assert_eq!(fields[5].instruction, r#"NEXTIF InvoiceTier = "Gold""#);
