    assert_eq!(fields[4].instruction, "PAGE");
    assert_eq!(fields[4].computed_result.as_deref(), Some("04"));
    assert_eq!(fields[5].kind, FieldKind::PageRef);
    assert_eq!(fields[5].instruction, "PAGEREF DecimalZeroSection \\h");
