    assert_eq!(fields[7].kind, FieldKind::Page);
    assert_eq!(fields[7].instruction, "PAGE");
    assert_eq!(fields[7].computed_result.as_deref(), Some("- 5 -"));
    assert_eq!(fields[8].kind, FieldKind::PageRef);
